module RefModule (
    input [1:0] bin,
    output [3:0] one_hot
);
    wire __one_hot_tmp = (bin == 2'b00) ? 4'b0001 :
                     (bin == 2'b01) ? 4'b0010 :
                     (bin == 2'b10) ? 4'b0100 :
                                      4'b1000;
    assign one_hot = __one_hot_tmp;
endmodule
